mapper.select:
SELECT * FROM ( SELECT rownum AS rnum, A.* FROM (
SELECT tc.test_id AS testId, tc.task_id AS taskId, tc.milestone_version AS milestoneVersion, tc.project_id AS projectId, tc.user_code AS userCode, tc.test_name AS testName, tc.created_at AS createdAt, tc.test_date AS testDate, tc.priority AS priority, tc.test_yn AS testYn, tc.test_manager AS testManager, tc.test_content AS testContent, tc.test_describe AS testDescribe, tc.coverage_status AS coverageStatus, u.user_name AS userName, t.task_title AS taskTitle, NVL(m.user_name, '-') AS managerName FROM test_case tc LEFT JOIN users u ON tc.user_code = u.user_code LEFT JOIN users m ON tc.test_manager = m.user_code LEFT JOIN task t ON tc.task_id = t.task_id WHERE tc.project_id = #{pId}
AND tc.test_name LIKE '%' || #{searchKeyword} || '%'
ORDER BY tc.created_at DESC
) A WHERE rownum <= #{offset} + #{pageSize} ) WHERE rnum > #{offset}
